import{_ as a,o as i,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"9. Definitions","description":"","frontmatter":{"title":"9. Definitions","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/mspp/operation/9-definitions.md","filePath":"ebas/mspp/operation/9-definitions.md"}'),s={name:"ebas/mspp/operation/9-definitions.md"};function n(r,e,l,c,h,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_9-definitions" tabindex="-1">9. Definitions <a class="header-anchor" href="#_9-definitions" aria-label="Permalink to &quot;9. Definitions&quot;">​</a></h1><p>In this Agreement:</p><p><strong>a.</strong> Act means the Fair Work Act 2009 (Cth).</p><p><strong>b.</strong> ADO means Accrued Day Off.</p><p><strong>c.</strong> Agreement means the Medical Scientists, Pharmacists and Psychologists Victorian Public Sector (Single Interest Employers) Enterprise Agreement 2021-2025.</p><p><strong>d.</strong> Audiologist if graduated prior to May 1999, is a university graduate who has completed a graduate diploma in audiology approved by the Audiological Society of Australia, or if graduated in May 1999 or thereafter, is a university graduate who has completed a masters degree in audiology approved by the Society, and who is eligible for membership of the Audiological Society of Australia.</p><p><strong>e.</strong> Associate Genetic Counsellor is defined in <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>.</p><p><strong>f.</strong> Clinical Perfusionist is defined in <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>.</p><p><strong>g.</strong> CMS means caseload management system.</p><p><strong>h.</strong> Departments and Sections shall be determined in the manner set out in sub- <a href="/eba/ebas/mspp/operation/6-savings-clause.html">clause 6.11</a> of <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>.</p><p><strong>i.</strong> Dietitian means a person who is eligible for full membership of the Dietitians Association of Australia.</p><p><strong>j.</strong> Employer shall mean an employer listed in <a href="/eba/ebas/mspp/schedules/1-employer-parties.html">Schedule 1</a> of this Agreement.</p><p><strong>k.</strong> FFPPOA means the beginning of the first full pay period commencing on or after a particular date.</p><p><strong>l.</strong> FWC means the Fair Work Commission.</p><p><strong>m.</strong> Genetic Counsellor is defined in <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>.</p><p><strong>n.</strong> HSR means a health and safety representative (including a deputy health and safety representative) elected under the OHS Act.</p><p><strong>o.</strong> Higher Qualifications Allowances shall mean allowances prescribed by salary for all purposes of this Agreement.</p><p><strong>p.</strong> Medical Physicist means a person who is eligible for membership of the Australian College of Physical Scientists and Engineers in Medicine as a medical physicist.</p><p><strong>q.</strong> NES means the National Employment Standards, as set out in the Act.</p><p><strong>r.</strong> OHS Act means the Occupational and Health Safety Act 2004 (Vic).</p><p><strong>s.</strong> PBA means Psychology Board of Australia.</p><p><strong>t.</strong> Pharmacist means a person registered as such under the Health Practitioner Regulation National Law Act and any successor legislation and whose name appears on the register of the Pharmacy Board of Australia.</p><p><strong>u.</strong> Student Pharmacist means a person undertaking the course of Bachelor of Pharmacy at the Victorian College of Pharmacy, Monash University or an equivalent Pharmacy course recognised by the Pharmacy Board of Victoria, and who has not completed the Pharmacy III examinations.</p><p><strong>v.</strong> Pharmacist Intern means a person who has completed the course of Bachelor of Pharmacy at the Victorian College of Pharmacy, Monash University, or an equivalent Pharmacy course recognised by the Pharmacy Board of Victoria, and who is undergoing the practical training prescribed by the Pharmacy Board, prior to registration as a Pharmacist.</p><p><strong>w.</strong> Trainee Pharmacist means Pharmacist Intern.</p><p><strong>x.</strong> Psychologist means a person registered as a Psychologist by the Australian Health Practitioner Agency in partnership with the Psychology Board of Australia, including psychologists with provisional registration.</p><p><strong>y.</strong> Recognised Prior Service means service prior to the Employee’s employment with the Employer with:</p><p><strong>(i)</strong> An Employer listed in <a href="/eba/ebas/mspp/schedules/1-employer-parties.html">Schedule 1</a> of this Agreement;</p><p><strong>(ii)</strong> An institution or statutory body as defined in cl 67.2c) and 67.2j) of this Agreement, including Community Health Services;</p><p><strong>(iii)</strong> Forensicare; and/or</p><p><strong>(iv)</strong> The Australian Red Cross Lifeblood, Where the period of absence between engagements with a prior Employer referred to at (i) and the Employer is less than 3 months. Note: Recognised Prior Service will apply to Progression at <a href="/eba/ebas/mspp/classification-salaries/49-progression-through-pay-points.html">clause 49</a>; Personal Leave at <a href="/eba/ebas/mspp/leave/64-personal-carer-s-leave.html">clause 64.3b</a>; Parental leave at <a href="/eba/ebas/allied-health/leave/70-parental-leave.html">clause 70.3a</a> and Sabbatical leave at <a href="/eba/ebas/mspp/leave/76-sabbatical-leave.html">clause 76</a>. The following terms rely on the definition of ‘service’ in the Long Service Leave clause at subclause 67.5: Long Service Leave at <a href="/eba/ebas/mspp/leave/67-long-service-leave.html">clause 67</a>, Redundancy at subclause 32.2f, and Notice of Termination at subclause 31.1f.</p><p><strong>z.</strong> Scientist means a person:</p><p><strong>(i)</strong> who holds a Bachelor of Applied Science or Bachelor of Science or equivalent where ‘equivalent’ includes a degree awarded by an overseas tertiary institution which is recognised by the Federal Department of Education and Training as such; or</p><p><strong>(ii)</strong> who holds a post-graduate degree in science or applied science; or</p><p><strong>(iii)</strong> who is eligible for ordinary membership of the Neurophysiological Sciences Society of Australia; or</p><p><strong>(iv)</strong> who is eligible for ordinary membership of the Australian and New Zealand Society of Respiratory Science Ltd and/or Australian and New Zealand Sleep Science Association (ANZSSA) and/or Australian Council for Clinical Physiologists (ACCP); or</p><p><strong>(v)</strong> who prior to 1 December 1973 held an associate qualification conferred by the (then) Australian Institute of Medical Technologists.</p><p><strong>(vi)</strong> In the case of a scientist working in a pathology laboratory (however titled), a scientist means a person who: <strong>(A)</strong> has completed the requirements of an undergraduate or post graduate academic qualification acceptable for graduate membership of the Australian Institute of Medical Scientists, or who has completed the requirements of an undergraduate or post graduate academic qualification acceptable for membership of the Australasian Association</p><p>of Clinical Biochemists or the Australian Association for Microbiology; or <strong>(B)</strong> is eligible for ordinary membership of the Human Genetics Society of Australasia or who is eligible to be non-medical member of the Australian Society of Cytology <strong>(C)</strong> in accordance with the health service&#39;s laboratory protocols, authorise and validate tests results and assesses quality control. Where results are outside critical or delta check limits a scientist will review, verify and release results in accordance with the health service&#39;s laboratory protocols; <strong>(D)</strong> performs duties including but not limited to cross matching of blood, blood film morphology and the interpretation of genetic testing results.</p><p><strong>(vii)</strong> Where technicians and/or other laboratory staff are engaged in their work area, a scientist with appropriate qualifications and competencies will supervise the work of those staff. aa. Service has the same meaning as ‘service’ and ‘continuous service’ provided by section 22 of the Act, and also means any Recognised Prior Service. Note: This does not detract from the definition of ‘service’ in the Long Service Leave clause at 67.2 bb. SHPA shall mean the Society of Hospital Pharmacists of Australia. cc. Shiftworker – for the purposes of the NES, a shiftworker is an Employee who works for more than four ordinary hours on 10 or more weekends during the year in which their annual leave accrues. dd. Teaching hospital shall be deemed to be a hospital which is affiliated with, or recognised by, a Victorian University for the instruction of students in medicine. ee. Trainee Scientist means any Employee engaged in studies leading to the attainment of the qualification Bachelor of Applied Science (Laboratory Medicine) or equivalent. ff. Union shall mean the Health Services Union (HSU), comprised of the Health Services Union No. 4 Branch (which reflects the membership of three existing component associations in Victoria, namely, the Medical Scientists Associations of Victoria (MSAV), Victorian Psychologists Association (VPA) and the Association of Hospital Pharmacists (AHPA)), Health Services Union No. 2 Branch with respect to psychologists. gg. Unit shall for the purposes of <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a>, include Andrology, Biochemistry, Blood Banking, Cardiology, Cardio Vascular Perfusion, Clinical Pharmacology, Cytogenetics, Cytology, Embryology, Endocrinology, Gastroenterology, Haematology, Histopathology, IVF Sciences, Immunology, Intensive Care, Lung Function, Medical Physics, Microbiology, Neuropathology, Neurophysiology, Physical Sciences, Renal Dialysis, Renal Unit, Tissue Typing, Vascular Unit or Virology. hh. VHIA means the Victorian Hospitals’ Industrial Association. ii. Week for the purpose of this Agreement a week shall be deemed to commence at midnight on a Sunday.</p><p>Plain language terms: glossary, meanings.</p>',41)])])}const m=a(s,[["render",n]]);export{g as __pageData,m as default};
